"},{"routine_name":"is_admin_of_condo","function_definition":"CREATE OR REPLACE FUNCTION public.is_admin_of_condo(condo_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_role text;
  v_condo_id uuid;
BEGIN
  SELECT papel_sistema, condominio_id
    INTO v_role, v_condo_id
    FROM perfil
   WHERE id = auth.uid();

  RETURN v_condo_id = condo_id
     AND lower(v_role) = ANY(ARRAY[
       'síndico', 'sindico', 'admin',
       'síndico (a)', 'sindico (a)',
       'síndico(a)', 'sindico(a)'
     ]);
END;
$function$
"},{"routine_name":"lista_add_points","function_definition":"CREATE OR REPLACE FUNCTION public.lista_add_points(p_user_id uuid, p_points integer)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  INSERT INTO lista_user_points (user_id, total_points, weekly_points, reports_count, rank_title)
  VALUES (p_user_id, p_points, p_points, 1, 'Iniciante')
  ON CONFLICT (user_id) DO UPDATE SET
    total_points = lista_user_points.total_points + p_points,
    weekly_points = lista_user_points.weekly_points + p_points,
    reports_count = lista_user_points.reports_count + 1,
    rank_title = CASE
      WHEN lista_user_points.total_points + p_points >= 1000 THEN 'Mestre do Preço'
      WHEN lista_user_points.total_points + p_points >= 500 THEN 'Caçador de Oferta'
      WHEN lista_user_points.total_points + p_points >= 200 THEN 'Fiscal de Preço'
      WHEN lista_user_points.total_points + p_points >= 50 THEN 'Colaborador'
      ELSE 'Iniciante'
    END,
    updated_at = now();
END;
$function$
"},{"routine_name":"lista_check_price_alerts","function_definition":"CREATE OR REPLACE FUNCTION public.lista_check_price_alerts()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  alert_record RECORD;
BEGIN
  FOR alert_record IN
    SELECT a.id, a.user_id, a.target_price, a.variant_id,
           v.variant_name, b.name as product_name, b.icon_emoji,
           s.name as supermarket_name
    FROM lista_price_alerts a
    JOIN lista_product_variants v ON v.id = a.variant_id
    JOIN lista_products_base b ON b.id = v.base_product_id
    LEFT JOIN lista_supermarkets s ON s.id = a.supermarket_id
    WHERE a.is_active = true
      AND a.is_triggered = false
      AND a.variant_id = NEW.variant_id
      AND (a.supermarket_id IS NULL OR a.supermarket_id = NEW.supermarket_id)
      AND NEW.price <= a.target_price
  LOOP
    UPDATE lista_price_alerts
    SET is_triggered = true,
        current_price = NEW.price,
        triggered_at = now(),
        updated_at = now()
    WHERE id = alert_record.id;
  END LOOP;

  RETURN NEW;
END;
$function$
"},{"routine_name":"lista_increment_confirmations","function_definition":"CREATE OR REPLACE FUNCTION public.lista_increment_confirmations(p_price_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  UPDATE lista_prices_raw
  SET confirmations = confirmations + 1,
      confidence_score = LEAST(1.0, confidence_score + 0.1)
  WHERE id = p_price_id;

  -- Também atualiza confidence no prices_current
  UPDATE lista_prices_current pc
  SET confidence_score = LEAST(1.0, pc.confidence_score + 0.05)
  FROM lista_prices_raw pr
  WHERE pr.id = p_price_id
    AND pc.sku_id = pr.sku_id
    AND pc.supermarket_id = pr.supermarket_id;
END;
$function$
