AS $function$
DECLARE
  v_thread RECORD;
  v_service_key TEXT;
BEGIN
  -- Only fire for admin messages
  IF NOT COALESCE(NEW.is_admin, false) THEN
    RETURN NEW;
  END IF;

  -- Get thread info
  SELECT id, resident_id, condominio_id, assunto INTO v_thread
  FROM public.fale_sindico_threads
  WHERE id = NEW.thread_id;

  IF v_thread IS NULL THEN
    RETURN NEW;
  END IF;

  v_service_key := coalesce(
    current_setting('app.settings.service_role_key', true),
    'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF2eXB5YXh0aHZnYXlicGxud3h1Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjIxOTk3NCwiZXhwIjoyMDg3Nzk1OTc0fQ.Y-t_4wRc8HNGPbmZJM4leUaB6m3rqMIZB75wr1VlK9s'
  );

