"},{"routine_name":"tr_fn_perfil_welcome","function_definition":"CREATE OR REPLACE FUNCTION public.tr_fn_perfil_welcome()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_condo_nome TEXT;
  v_service_key TEXT;
  v_cod_interno_1 TEXT;
  v_cod_interno_2 TEXT;
  v_msg1 TEXT;
  v_msg2 TEXT;
BEGIN
  -- Only fire when botconversa_id is set for the FIRST time (NULL -> non-NULL)
  IF OLD.botconversa_id IS NOT NULL THEN
    RETURN NEW;
  END IF;
  IF NEW.botconversa_id IS NULL OR TRIM(NEW.botconversa_id) = '' THEN
    RETURN NEW;
  END IF;

  -- Check if user opted out of WhatsApp notifications
  IF NEW.notificacoes_whatsapp IS FALSE THEN
    RETURN NEW;
  END IF;

  -- 1. Get condominium name
  SELECT nome INTO v_condo_nome
  FROM public.condominios WHERE id = NEW.condominio_id LIMIT 1;

  -- 2. Generate random 5-char codes (anti-ban for Meta)
  v_cod_interno_1 := substr(md5(random()::text), 1, 5);
  v_cod_interno_2 := substr(md5(random()::text || clock_timestamp()::text), 1, 5);

  -- 3. Build message 1 — Welcome
  v_msg1 := '😀 ' || COALESCE(v_condo_nome, 'Condomínio') || E'\n\n'
    || 'Olá ' || COALESCE(SPLIT_PART(NEW.nome_completo, ' ', 1), 'Morador') || ', seu cadastro foi feito com sucesso.' || E'\n\n'
    || 'Em breve o Adm/Síndico do ' || COALESCE(v_condo_nome, 'Condomínio') || ' irá liberar seu acesso.' || E'\n\n'
    || 'Condomeet agradece!' || E'\n'
    || 'Cód interno: ' || v_cod_interno_1;

  -- 4. Build message 2 — App info (static)
  v_msg2 := 'Ah, esse é número do aplicativo Condomeet.' || E'\n\n'
    || 'Cadastre nosso número no seu celular!' || E'\n\n'
    || 'Se precisar falar com o suporte do aplicativo Condomeet, cadastre no seu celular para não perder informação.' || E'\n\n'
    || 'Não temos informações internas do Condomínio.' || E'\n\n'
    || 'Se quiser saber das nossas novidades, siga a gente:' || E'\n\n'
    || 'www.instagram.com/condomeet.app' || E'\n\n'
    || 'Seja Bem vindo(a)!' || E'\n'
    || 'Cód interno: ' || v_cod_interno_2;

  -- 5. WhatsApp via botconversa-send (two messages with 5s delay)
  v_service_key := coalesce(
    current_setting('app.settings.service_role_key', true),
    'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF2eXB5YXh0aHZnYXlicGxud3h1Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjIxOTk3NCwiZXhwIjoyMDg3Nzk1OTc0fQ.Y-t_4wRc8HNGPbmZJM4leUaB6m3rqMIZB75wr1VlK9s'
  );

  BEGIN
    PERFORM net.http_post(
      url     := 'https://avypyaxthvgaybplnwxu.supabase.co/functions/v1/botconversa-send',
      headers := jsonb_build_object(
        'Content-Type', 'application/json',
        'Authorization', 'Bearer ' || v_service_key
      ),
      body    := jsonb_build_object(
        'msg', v_msg1,
        'tipo', 'texto',
        'condominio_id', NEW.condominio_id,
        'modo_envio', 'por_botconversa',
        'botconversa_id', NEW.botconversa_id,
        'tipo_notificacao', 'boas_vindas',
        'msg2', v_msg2,
        'msg2_delay_ms', 5000
      )
    );
  EXCEPTION WHEN OTHERS THEN
    RAISE WARNING 'botconversa-send (welcome) call failed: %', SQLERRM;
  END;

  RETURN NEW;
END;
$function$
"},{"routine_name":"tr_fn_perfil_welcome_uazapi","function_definition":"CREATE OR REPLACE FUNCTION public.tr_fn_perfil_welcome_uazapi()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_service_key TEXT;
BEGIN
  -- On INSERT: only fire if whatsapp is set
  IF TG_OP = 'INSERT' THEN
    IF NEW.whatsapp IS NULL OR TRIM(NEW.whatsapp) = '' THEN
      RETURN NEW;
    END IF;
  END IF;

  -- On UPDATE: only fire if whatsapp changed from null/empty to non-empty
  IF TG_OP = 'UPDATE' THEN
    IF (OLD.whatsapp IS NOT NULL AND TRIM(OLD.whatsapp) <> '') THEN
      -- Already had whatsapp, not a first-time set
      RETURN NEW;
    END IF;
    IF NEW.whatsapp IS NULL OR TRIM(NEW.whatsapp) = '' THEN
      RETURN NEW;
    END IF;
  END IF;

  v_service_key := coalesce(
    current_setting('app.settings.service_role_key', true),
    'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF2eXB5YXh0aHZnYXlicGxud3h1Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjIxOTk3NCwiZXhwIjoyMDg3Nzk1OTc0fQ.Y-t_4wRc8HNGPbmZJM4leUaB6m3rqMIZB75wr1VlK9s'
  );

  PERFORM net.http_post(
    url     := coalesce(
                 current_setting('app.settings.supabase_url', true),
                 'https://avypyaxthvgaybplnwxu.supabase.co'
               ) || '/functions/v1/welcome-notify',
    headers := jsonb_build_object(
      'Content-Type',  'application/json',
      'Authorization', 'Bearer ' || v_service_key
    ),
    body    := jsonb_build_object(
      'perfil_id',     NEW.id,
      'condominio_id', NEW.condominio_id
    )
  );

  RETURN NEW;

EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'tr_fn_perfil_welcome_uazapi failed: %', SQLERRM;
  RETURN NEW;
END;
$function$
"},{"routine_name":"tr_fn_reserva_criada","function_definition":"CREATE OR REPLACE FUNCTION public.tr_fn_reserva_criada()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_service_key TEXT;
  v_area_nome TEXT;
  v_auto_aprovacao BOOLEAN;
  v_action TEXT;
BEGIN
  -- Get area info (column is "local", not "nome")
  SELECT COALESCE(local, outro_local, ''), aprovacao_automatica INTO v_area_nome, v_auto_aprovacao
  FROM public.areas_comuns
  WHERE id = NEW.area_id;

  -- Determine action based on auto-approval
  IF v_auto_aprovacao IS TRUE THEN
    v_action := 'auto_approved';
  ELSE
    v_action := 'pending_approval';
  END IF;

  v_service_key := coalesce(
    current_setting('app.settings.service_role_key', true),
    'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF2eXB5YXh0aHZnYXlicGxud3h1Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjIxOTk3NCwiZXhwIjoyMDg3Nzk1OTc0fQ.Y-t_4wRc8HNGPbmZJM4leUaB6m3rqMIZB75wr1VlK9s'
  );

  PERFORM net.http_post(
    url     := coalesce(current_setting('app.settings.supabase_url', true), 'https://avypyaxthvgaybplnwxu.supabase.co') || '/functions/v1/reserva-notify',
    headers := jsonb_build_object('Content-Type', 'application/json', 'Authorization', 'Bearer ' || v_service_key),
    body    := jsonb_build_object(
      'action',        v_action,
      'reserva_id',    NEW.id,
      'user_id',       NEW.user_id,
      'condominio_id', NEW.condominio_id,
      'area_nome',     COALESCE(v_area_nome, ''),
      'data_reserva',  COALESCE(NEW.data_reserva::text, ''),
      'bloco_destino', COALESCE(NEW.bloco_destino, ''),
      'apto_destino',  COALESCE(NEW.apto_destino, '')
    )
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'tr_fn_reserva_criada failed: %', SQLERRM;
  RETURN NEW;
END;
$function$
"},{"routine_name":"tr_fn_reserva_status_changed","function_definition":"CREATE OR REPLACE FUNCTION public.tr_fn_reserva_status_changed()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_service_key TEXT;
  v_area_nome TEXT;
  v_action TEXT;
BEGIN
  -- Only fire when status actually changes
  IF OLD.status = NEW.status THEN
    RETURN NEW;
  END IF;

  -- Only notify for approved or rejected
  IF NEW.status = 'aprovado' OR NEW.status = 'approved' THEN
    v_action := 'approved';
  ELSIF NEW.status = 'recusado' OR NEW.status = 'rejected' THEN
    v_action := 'rejected';
  ELSE
    RETURN NEW;
  END IF;

  SELECT nome INTO v_area_nome FROM public.areas_comuns WHERE id = NEW.area_id;

  v_service_key := coalesce(
    current_setting('app.settings.service_role_key', true),
    'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF2eXB5YXh0aHZnYXlicGxud3h1Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjIxOTk3NCwiZXhwIjoyMDg3Nzk1OTc0fQ.Y-t_4wRc8HNGPbmZJM4leUaB6m3rqMIZB75wr1VlK9s'
  );

  PERFORM net.http_post(
    url     := coalesce(current_setting('app.settings.supabase_url', true), 'https://avypyaxthvgaybplnwxu.supabase.co') || '/functions/v1/reserva-notify',
    headers := jsonb_build_object('Content-Type', 'application/json', 'Authorization', 'Bearer ' || v_service_key),
    body    := jsonb_build_object(
      'action',       v_action,
      'reserva_id',   NEW.id,
      'user_id',      NEW.user_id,
      'condominio_id', NEW.condominio_id,
      'area_nome',    COALESCE(v_area_nome, ''),
      'data_reserva', COALESCE(NEW.data_reserva::text, '')
    )
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'tr_fn_reserva_status_changed failed: %', SQLERRM;
  RETURN NEW;
END;
$function$
"},{"routine_name":"tr_fn_resolve_botconversa","function_definition":"CREATE OR REPLACE FUNCTION public.tr_fn_resolve_botconversa()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_service_key TEXT;
  v_whatsapp TEXT;
BEGIN
  -- Determine the whatsapp value to use
  v_whatsapp := NEW.whatsapp;

  -- Only proceed if whatsapp is non-empty
  IF v_whatsapp IS NULL OR TRIM(v_whatsapp) = '' THEN
    RETURN NEW;
  END IF;

  -- On UPDATE, only proceed if whatsapp actually changed
  IF TG_OP = 'UPDATE' THEN
    IF OLD.whatsapp IS NOT DISTINCT FROM NEW.whatsapp THEN
      RETURN NEW;
    END IF;
  END IF;

  -- Get service key for auth
  v_service_key := coalesce(
    current_setting('app.settings.service_role_key', true),
    'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF2eXB5YXh0aHZnYXlicGxud3h1Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjIxOTk3NCwiZXhwIjoyMDg3Nzk1OTc0fQ.Y-t_4wRc8HNGPbmZJM4leUaB6m3rqMIZB75wr1VlK9s'
  );

  BEGIN
    PERFORM net.http_post(
      url     := 'https://avypyaxthvgaybplnwxu.supabase.co/functions/v1/botconversa-resolve-subscriber',
      headers := jsonb_build_object(
        'Content-Type', 'application/json',
        'Authorization', 'Bearer ' || v_service_key
      ),
      body    := jsonb_build_object(
        'perfil_id', NEW.id::text,
        'whatsapp', v_whatsapp,
        'nome_completo', COALESCE(NEW.nome_completo, '')
      )
    );
  EXCEPTION WHEN OTHERS THEN
    RAISE WARNING 'botconversa-resolve-subscriber call failed: %', SQLERRM;
  END;

  RETURN NEW;
END;
$function$
