"},{"routine_name":"update_profile","function_definition":"CREATE OR REPLACE FUNCTION public.update_profile(p_user_id uuid, p_nome_completo text DEFAULT NULL::text, p_whatsapp text DEFAULT NULL::text, p_tipo_morador text DEFAULT NULL::text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  UPDATE perfil
  SET nome_completo  = COALESCE(p_nome_completo, nome_completo),
      whatsapp       = COALESCE(p_whatsapp, whatsapp),
      tipo_morador   = COALESCE(p_tipo_morador, tipo_morador),
      updated_at     = now()
